        "seminar": "marques-sola",
        "activity": "Conversaciones. El estado de las cosas",
        "title": "Carlos Marqués-Marcet, Eduard Sola, Jaione Camborda y Valentina Viso",
        "location": "Cineteca Matadero - Sala Azcona",
